sql:
SELECT COUNT(*) AS active_configs_count
FROM config_data
WHERE is_active = 1;

SELECT function
FROM config_data
WHERE created_by = 1;

SELECT COUNT(component_name) AS active_components_count
FROM digital_components
WHERE status = 'active';

SELECT component_name
FROM digital_components
WHERE status = 'active';

SELECT import_date, created_by, import_status
FROM config_imports
WHERE import_status = 'completed';

SELECT COUNT(*) 
FROM config_exports 
WHERE export_status = 'completed';

external_knowledge:
; A configuration data is considered 'Active' if its 'is_active' value equals 1, implying it is currently in use; 
; The 'created_at' timestamp represents when the configuration data was initially added to the system; 
; The 'updated_at' timestamp indicates the last time the configuration data was modified.

